#[derive(Debug, Default, Clone)]
pub struct VideoTextureUpdate {
    pub position: f64,
    pub play: bool,
    pub r#loop: bool,
    pub decoded_time: i128,
    pub asset_id: i32,
}

impl MemoryPackable for VideoTextureUpdate {
    fn pack(&mut self, packer: &mut MemoryPacker<'_>) {
        packer.write(&self.asset_id);
        packer.write(&self.position);
        packer.write_packed_bools_array([
            self.play,
            self.r#loop,
            false,
            false,
            false,
            false,
            false,
            false,
        ]);
    }
    fn unpack<P: MemoryPackerEntityPool>(
        &mut self,
        unpacker: &mut MemoryUnpacker<'_, '_, P>,
    ) -> Result<(), WireDecodeError> {
        self.asset_id = unpacker.read()?;
        self.position = unpacker.read()?;
        let __p = unpacker.read_packed_bools()?;
        self.play = __p.bit0;
        self.r#loop = __p.bit1;
        self.decoded_time = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_nanos() as i128;
        Ok(())
    }
}

