#[derive(Clone, Copy, Debug, Default, PartialEq)]
#[repr(i32)]
pub enum RectOrientation {
    #[default]
    Default = 0,
    Clockwise90 = 1,
    UpsideDown180 = 2,
    CounterClockwise90 = 3,
}

impl MemoryPackable for RectOrientation {
    fn pack(&mut self, packer: &mut MemoryPacker<'_>) {
        packer.write(&(*self as i32));
    }
    fn unpack<P: MemoryPackerEntityPool>(
        &mut self,
        unpacker: &mut MemoryUnpacker<'_, '_, P>,
    ) -> Result<(), WireDecodeError> {
        let raw = unpacker.read::<i32>()?;
        *self = match raw {
            0 => Self::Default,
            1 => Self::Clockwise90,
            2 => Self::UpsideDown180,
            3 => Self::CounterClockwise90,
            _ => {
                trace!("invalid RectOrientation wire value {}; using default", raw);
                Self::Default
            }
        };
        Ok(())
    }
}

impl EnumRepr for RectOrientation {
    fn as_i32(self) -> i32 {
        self as i32
    }
    fn from_i32(i: i32) -> Self {
        match i {
            0 => Self::Default,
            1 => Self::Clockwise90,
            2 => Self::UpsideDown180,
            3 => Self::CounterClockwise90,
            _ => {
                trace!("invalid RectOrientation discriminant {}; using default", i);
                Self::Default
            }
        }
    }
}

